import 'package:flutter/material.dart';
import 'package:flutter/widgets.dart' show Element;

void main() => runApp(const MaterialApp(home: TreePeekPage()));

class TreePeekPage extends StatelessWidget {
  const TreePeekPage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Element peek')),
    body: Center(
      child: FilledButton(
        onPressed: () => _dumpAncestors(context),
        child: const Text('Log my ancestors'),
      ),
    ),
  );

  // BuildContext IS an Element. We can walk up the tree from it.
  void _dumpAncestors(BuildContext context) {
    // context.visitAncestorElements walks UP the Element tree.
    debugPrint('--- ancestors from FilledButton (bottom to top) ---');
    var depth = 0;
    context.visitAncestorElements((Element el) {
      depth++;
      debugPrint('  $depth: ${el.widget.runtimeType}');
      return depth < 20;   // stop after 20 levels
    });

    // context.findAncestorWidgetOfExactType — the low-level lookup
    final materialApp = context.findAncestorWidgetOfExactType<MaterialApp>();
    debugPrint('nearest MaterialApp: ${materialApp != null}');

    // dependOnInheritedWidgetOfExactType is what Theme.of / MediaQuery.of use
    final theme = Theme.of(context);
    debugPrint('primary color: ${theme.colorScheme.primary}');
  }
}

// Sample output (abbreviated):
//   1: FilledButton
//   2: Center
//   3: MediaQuery      ← InheritedWidgets show up in the chain
//   4: Padding
//   5: SafeArea
//   6: Scaffold
//   7: HeroControllerScope
//   8: Navigator
//  ...
//   ~20: MaterialApp
// nearest MaterialApp: true
// primary color: Color(0xff6750a4)
